import{c as a,Q as t,j as n,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"OpenClaw — Telegram bot","description":"Link your Telegram, send your first command.","frontmatter":{"title":"OpenClaw — Telegram bot","description":"Link your Telegram, send your first command."},"headers":[],"relativePath":"openclaw/telegram-bot.md","filePath":"openclaw/telegram-bot.md","lastUpdated":1780196777000}'),i={name:"openclaw/telegram-bot.md"};function o(l,e,p,r,d,c){return t(),n("div",null,[...e[0]||(e[0]=[s(`<div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>This surface is still being hardened and isn&#39;t part of the <a href="/guide/">Testing Guide</a>. The page below describes the intended design. To evaluate MuHaven today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a>.</p></div><h1 id="the-muhaven-telegram-bot" tabindex="-1">The MuHaven Telegram bot <a class="header-anchor" href="#the-muhaven-telegram-bot" aria-label="Permalink to &quot;The MuHaven Telegram bot&quot;">​</a></h1><p><code>@muhaven_bot</code> is MuHaven&#39;s phone-first surface. You link it to your MuHaven wallet once, and from then on you can drive read tools and tier-1 (≤$200) buys with a single tap.</p><h2 id="step-1-—-start-a-chat-with-the-bot" tabindex="-1">Step 1 — Start a chat with the bot <a class="header-anchor" href="#step-1-—-start-a-chat-with-the-bot" aria-label="Permalink to &quot;Step 1 — Start a chat with the bot&quot;">​</a></h2><p>Open Telegram and search for <code>@muhaven_bot</code> (or the staging variant <code>@muhaven_stage_bot</code> if you&#39;re on stage). Tap <strong>Start</strong>. The bot replies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Welcome to MuHaven 🪙</span></span>
<span class="line"><span></span></span>
<span class="line"><span>To link this Telegram account to your MuHaven wallet, run /link</span></span>
<span class="line"><span>in this chat. I&#39;ll give you a one-time code; paste it into your</span></span>
<span class="line"><span>dashboard at https://muhaven.app/agent → Settings → Telegram.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This is the only time you&#39;ll need a passkey for Telegram — once</span></span>
<span class="line"><span>linked, sub-$200 buys are one-tap.</span></span></code></pre></div><h2 id="step-2-—-link-your-muhaven-wallet" tabindex="-1">Step 2 — Link your MuHaven wallet <a class="header-anchor" href="#step-2-—-link-your-muhaven-wallet" aria-label="Permalink to &quot;Step 2 — Link your MuHaven wallet&quot;">​</a></h2><p>In the Telegram chat:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/link</span></span></code></pre></div><p>The bot replies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔗 Link code: ABCD-1234</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Open https://muhaven.app/agent → Settings → Telegram</span></span>
<span class="line"><span>2. Paste this code and confirm with your passkey</span></span>
<span class="line"><span>3. Once linked, your audit log will show &quot;telegram_link_consumed&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This code expires in 5 minutes.</span></span></code></pre></div><p>On the dashboard:</p><ol><li>Navigate to <code>/agent → Settings → Telegram</code>.</li><li>Paste <code>ABCD-1234</code>.</li><li>Confirm with your passkey.</li></ol><p>A small notification arrives in your Telegram chat: <code>✅ Linked. Try /portfolio.</code></p><h2 id="step-3-—-send-your-first-command" tabindex="-1">Step 3 — Send your first command <a class="header-anchor" href="#step-3-—-send-your-first-command" aria-label="Permalink to &quot;Step 3 — Send your first command&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>/portfolio</code></td><td><code>muhaven.read.portfolio</code> — shows your aggregate token list.</td></tr><tr><td><code>/yields RWA1</code></td><td><code>muhaven.read.yields</code> for RWA1 — last 5 epochs.</td></tr><tr><td><code>/buy 50 RWA1</code></td><td>Tier-classified buy. ≤$200 → inline button.</td></tr><tr><td><code>/claim RWA1 5</code></td><td>Claim RWA1 yield for epoch 5.</td></tr><tr><td><code>/pause</code></td><td>Pause your agent.</td></tr><tr><td><code>/audit</code></td><td>Show last 10 audit rows.</td></tr><tr><td><code>/help</code></td><td>List all commands.</td></tr></tbody></table><h3 id="example-a-tier-1-buy" tabindex="-1">Example: a tier-1 buy <a class="header-anchor" href="#example-a-tier-1-buy" aria-label="Permalink to &quot;Example: a tier-1 buy&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/buy 50 RWA1</span></span></code></pre></div><p>The bot replies with an inline keyboard:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You&#39;re about to buy 50 mhUSDC of RWA1.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Quote: ~49.85 shares @ NAV $1.003</span></span>
<span class="line"><span>   Tier:  Inline (≤$200)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   [✅ Confirm]   [❌ Cancel]</span></span></code></pre></div><p>Tap <strong>Confirm</strong>. The bot:</p><ol><li>Validates the tap is from the same Telegram user_id that&#39;s linked to the MuHaven wallet.</li><li>Calls the inline-confirmation endpoint with the service-secret + user-id assertion.</li><li>Settles on-chain.</li><li>Replies: <code>✅ Settled. Tx: 0xabc...</code></li></ol><p>The whole flow is one tap.</p><h3 id="example-a-tier-2-buy-200-5k" tabindex="-1">Example: a tier-2 buy ($200-$5K) <a class="header-anchor" href="#example-a-tier-2-buy-200-5k" aria-label="Permalink to &quot;Example: a tier-2 buy ($200-$5K)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/buy 1000 RWA1</span></span></code></pre></div><p>The bot replies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You&#39;re about to buy 1000 mhUSDC of RWA1.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Quote: ~996.5 shares @ NAV $1.003</span></span>
<span class="line"><span>   Tier:  Mini-App OTP ($200–$5K)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   OTP: 184329 (valid 5 minutes). Open the Mini App and enter it.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   [📱 Open Mini App]</span></span></code></pre></div><p>Tap <strong>Open Mini App</strong>. The Telegram Mini App opens inside Telegram showing:</p><ul><li>The cleartext quote (mhUSDC amount, share estimate, NAV).</li><li>A 6-digit OTP input.</li></ul><p>Enter the OTP from the bot message and tap <strong>Confirm</strong>.</p><p>Settlement and a Telegram reply mirror the tier-1 flow.</p><h3 id="example-a-tier-3-buy-5k" tabindex="-1">Example: a tier-3 buy (&gt;$5K) <a class="header-anchor" href="#example-a-tier-3-buy-5k" aria-label="Permalink to &quot;Example: a tier-3 buy (&gt;$5K)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/buy 10000 RWA1</span></span></code></pre></div><p>The bot replies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You&#39;re about to buy 10,000 mhUSDC of RWA1.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   Tier: Passkey deep-link (&gt;$5K)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   For amounts above $5K, you confirm with your passkey on the</span></span>
<span class="line"><span>   dashboard. Tap the button below to open the confirmation page.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   [🔑 Open passkey dashboard]</span></span></code></pre></div><p>Tap the button. Your default browser opens to <code>https://muhaven.app/agent/confirm?intent=oci_xxx</code>. The page shows the same cleartext preview as ConfirmModal; you confirm with your passkey. The bot updates the chat to <code>✅ Settled.</code> once the on-chain settlement notification arrives via SSE.</p><h2 id="privacy-properties" tabindex="-1">Privacy properties <a class="header-anchor" href="#privacy-properties" aria-label="Permalink to &quot;Privacy properties&quot;">​</a></h2><ul><li>The bot <strong>never sees your MuHaven wallet signing key</strong> — it operates through the backend over HTTPS with bot service-secret + Telegram <code>initData</code> HMAC verification.</li><li>The bot <strong>never sees encrypted balances</strong> — same backend-aggregate property as MCP.</li><li>The bot edge sees your Telegram chat_id, user_id, and the command text. Telegram&#39;s servers see your message (transport-level encryption, not E2EE in standard chat).</li><li>The Mini App is served from <code>tg.muhaven.app</code> with a strict CSP — no third-party trackers.</li><li>The OTP delivery channel (today: passkey-auth&#39;d webhook) keeps the OTP out of the Telegram bot session entirely.</li></ul><h2 id="bot-quirks" tabindex="-1">Bot quirks <a class="header-anchor" href="#bot-quirks" aria-label="Permalink to &quot;Bot quirks&quot;">​</a></h2><ul><li><strong>Inline buttons assume <code>chat.type === &#39;private&#39;</code>.</strong> Group chats and channels are explicitly refused — the bot won&#39;t action <code>/buy</code> in a group.</li><li><strong>The <code>telegram_links</code> table stores both <code>telegramChatId</code> (PK) and <code>telegramUserId</code></strong> (Mini-App lookup). The two aren&#39;t equal outside private chats — the bot enforces <code>chat.type === &#39;private&#39; &amp;&amp; from.id === chat.id</code> for callback queries.</li><li><strong>Service-secret discipline:</strong> the inline-confirm and inline-deny endpoints reject any intent whose tier isn&#39;t <code>inline</code>. A compromised bot worker cannot escalate a <code>mini_app_otp</code> or <code>passkey_deeplink</code> intent without going through the user-driven surface.</li></ul><h2 id="unlinking" tabindex="-1">Unlinking <a class="header-anchor" href="#unlinking" aria-label="Permalink to &quot;Unlinking&quot;">​</a></h2><p>To unlink Telegram from your MuHaven wallet:</p><ol><li>On the dashboard: <code>/agent → Settings → Telegram → Unlink</code>.</li><li>Confirm with your passkey.</li><li>The bot replies: <code>❌ Unlinked. Run /link again to re-bind.</code></li></ol><p>Your MuHaven wallet and audit log are unaffected — only the bot ↔ wallet binding is severed.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/openclaw/confirmation-tiers">Three confirmation tiers</a> — the classifier and per-tier flow detail.</li><li><a href="/openclaw/tools">Available tools</a> — what each Telegram command maps to.</li><li><a href="/openclaw/troubleshooting">Troubleshooting</a> — common Telegram + skill issues.</li></ul>`,46)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
